@namespace sv_7a595e577ddf441ab121ae12329b65bd.Components.Pages.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2">
            @if (CanMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary me-1" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@namespace sv_7a595e577ddf441ab121ae12329b65bd.Components.Pages.Board

<div class="card border-primary mt-2">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <button class="btn btn-sm btn-primary me-1" @onclick="Save">Save</button>
        <button class="btn btn-sm btn-secondary" @onclick="OnCancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private async Task Save()
    {
        if (!string.IsNullOrWhiteSpace(title))
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
    }
}

@namespace sv_7a595e577ddf441ab121ae12329b65bd.Components.Pages.Board

<div class="col-md-4">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => MoveLeft(task)"
                          OnMoveRight="() => MoveRight(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
            }
            else
            {
                <button class="btn btn-sm btn-outline-primary w-100 mt-2" @onclick="() => showForm = true">+ Add Task</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showForm;

    private async Task MoveLeft(TaskItem task) => await OnMoveLeft.InvokeAsync(task);
    private async Task MoveRight(TaskItem task) => await OnMoveRight.InvokeAsync(task);

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync(data);
        showForm = false;
    }
}

@page "/board"
@namespace sv_7a595e577ddf441ab121ae12329b65bd.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                TodoCount="TodoTasks.Count"
                InProgressCount="InProgressTasks.Count"
                DoneCount="DoneTasks.Count"
                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="row">
        <BoardColumn ColumnName="To Do"
                     Tasks="TodoTasks"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="task => MoveTask(task, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="InProgressTasks"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, \"To Do\")"
                     OnMoveRight="task => MoveTask(task, \"Done\")"
                     OnAddTask="data => AddTask(data, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="DoneTasks"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> FilteredTasks => string.IsNullOrWhiteSpace(searchText)
        ? allTasks
        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TodoTasks => FilteredTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => FilteredTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => FilteredTasks.Where(t => t.Status == "Done").ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

