@namespace sv_7a595e577ddf441ab121ae12329b65bd.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                TodoCount="TodoTasks.Count"
                InProgressCount="InProgressTasks.Count"
                DoneCount="DoneTasks.Count"
                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="row">
        <BoardColumn ColumnName="To Do"
                     Tasks="TodoTasks"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="task => MoveTask(task, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="InProgressTasks"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, \"To Do\")"
                     OnMoveRight="task => MoveTask(task, \"Done\")"
                     OnAddTask="data => AddTask(data, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="DoneTasks"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> FilteredTasks => string.IsNullOrWhiteSpace(searchText)
        ? allTasks
        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TodoTasks => FilteredTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => FilteredTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => FilteredTasks.Where(t => t.Status == "Done").ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}
"}

